mapper.select:
Select MIN(c.c_id) AS c_id,
c.c_name,
MIN(c.adcode) AS adcode,
c.polygon from counties c,county_dialect cd,languages l,
dialects d,subdialects s,accents a where c.c_id=cd.c_id and cd.l_id=l.l_id and cd.d_id=d.d_id and cd.s_id=s.s_id and
cd.a_id=a.a_id and l.l_name=#{language}
and d.d_name=#{dialect}
and s.s_name=#{subDialect}
and a.a_name=#{accent} group by c.c_name,c.polygon
